    VPMINUB Z7, Z6, Z9
    VPSUBB Z9, Z8, Z8          // d = |a-b|
    VPXORD Z4, Z8, Z9          // d-128 as s8
    VPDPBUSD Z9, Z8, Z0        // += d * (d-128)
    VPDPBUSD Z4, Z8, Z20       // += d * -128
    VMOVDQU64 64(SI), Z11      // a[64:128]
    VMOVDQU64 64(DI), Z12      // b[64:128]
