    VPMINUB Z12, Z11, Z14
    VPSUBB Z14, Z13, Z13
    VPXORD Z4, Z13, Z14
    VPDPBUSD Z14, Z13, Z1
    VPDPBUSD Z4, Z13, Z21
    ADDQ $128, SI
    ADDQ $128, DI
    DECQ CX
    JNZ lv512_loop128

lv512_tail64:
    TESTQ $64, DX
    JZ lv512_tail_mask
    VMOVDQU64 (SI), Z6
    VMOVDQU64 (DI), Z7
    VPMAXUB Z7, Z6, Z8
    VPMINUB Z7, Z6, Z9
    VPSUBB Z9, Z8, Z8
    VPXORD Z4, Z8, Z9
    VPDPBUSD Z9, Z8, Z0
    VPDPBUSD Z4, Z8, Z20
    ADDQ $64, SI
    ADDQ $64, DI

lv512_tail_mask:
    MOVQ DX, CX
    ANDQ $63, CX
    JZ lv512_reduce
    MOVQ $-1, AX
    BZHIQ CX, AX, AX
    KMOVQ AX, K1
    VMOVDQU8.Z (SI), K1, Z6    // masked-off bytes: a=b=0 so d=0
