    VPDPBUSD Z4, Z8, Z21

lv512_reduce:
    VPADDD Z1, Z0, Z0
    VPADDD Z21, Z20, Z20
    VPSUBD Z20, Z0, Z0         // l2 = acc - corr, per int32 lane
    VEXTRACTI64X4 $1, Z0, Y1
    VPADDD Y1, Y0, Y0
    VEXTRACTI128 $1, Y0, X1
    VPADDD X1, X0, X0
    VPSHUFD $0x4E, X0, X1
    VPADDD X1, X0, X0
    VPSHUFD $0xB1, X0, X1
    VPADDD X1, X0, X0
    VMOVD X0, AX
    VZEROUPPER
    MOVL AX, ret+24(FP)
    RET

// func dotByteAVXVNNIAsm(a, b *byte, n int) uint32
TEXT ·dotByteAVXVNNIAsm(SB), NOSPLIT, $0-28
    MOVQ a+0(FP), SI
    MOVQ b+8(FP), DI
    MOVQ n+16(FP), DX
    XORL BX, BX                // scalar tail accumulator
    VPXOR Y0, Y0, Y0           // dot accumulators, 4 chains
    VPXOR Y1, Y1, Y1
    VPXOR Y2, Y2, Y2
    VPXOR Y3, Y3, Y3
    VPXOR Y8, Y8, Y8           // correction accumulators (-128*sum a)
    VPXOR Y9, Y9, Y9
    VPXOR Y10, Y10, Y10
    VPXOR Y11, Y11, Y11
    MOVQ $0x8080808080808080, AX
    VMOVQ AX, X4
    VPBROADCASTQ X4, Y4        // 0x80: XOR maps u8 to s8; as s8 it is -128
    MOVQ DX, CX
    SHRQ $7, CX
    JZ dvv_tail64

dvv_loop128:
    VMOVDQU (SI), Y6           // a[0:32]
    VMOVDQU (DI), Y7           // b[0:32]
    VPXOR Y4, Y7, Y7           // b-128 as s8
    LONG $0x504DE2C4; BYTE $0xC7 // VPDPBUSD Y7, Y6, Y0 (VEX, AVX-VNNI)
    LONG $0x504D62C4; BYTE $0xC4 // VPDPBUSD Y4, Y6, Y8 (VEX, AVX-VNNI)
    VMOVDQU 32(SI), Y12        // a[32:64]
    VMOVDQU 32(DI), Y13
    VPXOR Y4, Y13, Y13
    LONG $0x501DC2C4; BYTE $0xCD // VPDPBUSD Y13, Y12, Y1 (VEX, AVX-VNNI)
    LONG $0x501D62C4; BYTE $0xCC // VPDPBUSD Y4, Y12, Y9 (VEX, AVX-VNNI)
    VMOVDQU 64(SI), Y6         // a[64:96]
    VMOVDQU 64(DI), Y7
    VPXOR Y4, Y7, Y7
    LONG $0x504DE2C4; BYTE $0xD7 // VPDPBUSD Y7, Y6, Y2 (VEX, AVX-VNNI)
    LONG $0x504D62C4; BYTE $0xD4 // VPDPBUSD Y4, Y6, Y10 (VEX, AVX-VNNI)
    VMOVDQU 96(SI), Y12        // a[96:128]
    VMOVDQU 96(DI), Y13
    VPXOR Y4, Y13, Y13
    LONG $0x501DC2C4; BYTE $0xDD // VPDPBUSD Y13, Y12, Y3 (VEX, AVX-VNNI)
    LONG $0x501D62C4; BYTE $0xDC // VPDPBUSD Y4, Y12, Y11 (VEX, AVX-VNNI)
    ADDQ $128, SI
    ADDQ $128, DI
    DECQ CX
    JNZ dvv_loop128

dvv_tail64:
    TESTQ $64, DX
    JZ dvv_tail32
    VMOVDQU (SI), Y6
    VMOVDQU (DI), Y7
    VPXOR Y4, Y7, Y7
    LONG $0x504DE2C4; BYTE $0xC7 // VPDPBUSD Y7, Y6, Y0 (VEX, AVX-VNNI)
    LONG $0x504D62C4; BYTE $0xC4 // VPDPBUSD Y4, Y6, Y8 (VEX, AVX-VNNI)
    VMOVDQU 32(SI), Y12
    VMOVDQU 32(DI), Y13
    VPXOR Y4, Y13, Y13
    LONG $0x501DC2C4; BYTE $0xCD // VPDPBUSD Y13, Y12, Y1 (VEX, AVX-VNNI)
    LONG $0x501D62C4; BYTE $0xCC // VPDPBUSD Y4, Y12, Y9 (VEX, AVX-VNNI)
    ADDQ $64, SI
    ADDQ $64, DI

dvv_tail32:
    TESTQ $32, DX
    JZ dvv_fold
    VMOVDQU (SI), Y6
    VMOVDQU (DI), Y7
    VPXOR Y4, Y7, Y7
    LONG $0x504DE2C4; BYTE $0xD7 // VPDPBUSD Y7, Y6, Y2 (VEX, AVX-VNNI)
    LONG $0x504D62C4; BYTE $0xD4 // VPDPBUSD Y4, Y6, Y10 (VEX, AVX-VNNI)
    ADDQ $32, SI
    ADDQ $32, DI

dvv_fold:
    // Fold the YMM accumulators to XMM before the sub-16-byte tails: a
    // VEX-128 VPDPBUSD zeroes bits 255:128 of its destination, so the XMM
    // tail steps may only touch accumulators that are already 128-bit.
    VPADDD Y1, Y0, Y0
    VPADDD Y3, Y2, Y2
    VPADDD Y2, Y0, Y0
    VPADDD Y9, Y8, Y8
    VPADDD Y11, Y10, Y10
    VPADDD Y10, Y8, Y8
    VEXTRACTI128 $1, Y0, X1
    VPADDD X1, X0, X0          // X0 = folded dot acc
    VEXTRACTI128 $1, Y8, X1
    VPADDD X1, X8, X8          // X8 = folded corr acc

    TESTQ $16, DX
    JZ dvv_tail8
    VMOVDQU (SI), X6
    VMOVDQU (DI), X7
    VPXOR X4, X7, X7
    LONG $0x5049E2C4; BYTE $0xC7 // VPDPBUSD X7, X6, X0 (VEX, AVX-VNNI)
    LONG $0x504962C4; BYTE $0xC4 // VPDPBUSD X4, X6, X8 (VEX, AVX-VNNI)
    ADDQ $16, SI
    ADDQ $16, DI

dvv_tail8:
    TESTQ $8, DX
    JZ dvv_tail_scalar
    VMOVQ (SI), X6             // upper 8 bytes zero: contribute 0 to both
    VMOVQ (DI), X7
    VPXOR X4, X7, X7
    LONG $0x5049E2C4; BYTE $0xC7 // VPDPBUSD X7, X6, X0 (VEX, AVX-VNNI)
    LONG $0x504962C4; BYTE $0xC4 // VPDPBUSD X4, X6, X8 (VEX, AVX-VNNI)
    ADDQ $8, SI
    ADDQ $8, DI

dvv_tail_scalar:
    MOVQ DX, CX
    ANDQ $7, CX
    JZ dvv_reduce

dvv_scalar:
    MOVBLZX (SI), R9
    MOVBLZX (DI), R10
    IMULL R10, R9
    ADDL R9, BX
    INCQ SI
    INCQ DI
    DECQ CX
    JNZ dvv_scalar

dvv_reduce:
    VPSUBD X8, X0, X0          // dot = acc - corr, per int32 lane
    VPSHUFD $0x4E, X0, X1
    VPADDD X1, X0, X0
    VPSHUFD $0xB1, X0, X1
    VPADDD X1, X0, X0
    VMOVD X0, AX
    ADDL BX, AX
    VZEROUPPER
    MOVL AX, ret+24(FP)
    RET

// func l2ByteAVXVNNIAsm(a, b *byte, n int) uint32
TEXT ·l2ByteAVXVNNIAsm(SB), NOSPLIT, $0-28
    MOVQ a+0(FP), SI
    MOVQ b+8(FP), DI
    MOVQ n+16(FP), DX
    XORL BX, BX
    VPXOR Y0, Y0, Y0           // squared-diff accumulators
    VPXOR Y1, Y1, Y1
    VPXOR Y8, Y8, Y8           // correction accumulators (-128*sum d)
    VPXOR Y9, Y9, Y9
    MOVQ $0x8080808080808080, AX
    VMOVQ AX, X4
    VPBROADCASTQ X4, Y4
    MOVQ DX, CX
    SHRQ $6, CX
    JZ lvv_tail32

lvv_loop64:
    VMOVDQU (SI), Y6           // a[0:32]
    VMOVDQU (DI), Y7           // b[0:32]
    VPMAXUB Y7, Y6, Y2
    VPMINUB Y7, Y6, Y3
    VPSUBB Y3, Y2, Y2          // d = |a-b|
    VPXOR Y4, Y2, Y3           // d-128 as s8
    LONG $0x506DE2C4; BYTE $0xC3 // VPDPBUSD Y3, Y2, Y0 (VEX, AVX-VNNI)
    LONG $0x506D62C4; BYTE $0xC4 // VPDPBUSD Y4, Y2, Y8 (VEX, AVX-VNNI)
    VMOVDQU 32(SI), Y12        // a[32:64]
    VMOVDQU 32(DI), Y13
    VPMAXUB Y13, Y12, Y14
    VPMINUB Y13, Y12, Y15
    VPSUBB Y15, Y14, Y14
    VPXOR Y4, Y14, Y15
    LONG $0x500DC2C4; BYTE $0xCF // VPDPBUSD Y15, Y14, Y1 (VEX, AVX-VNNI)
    LONG $0x500D62C4; BYTE $0xCC // VPDPBUSD Y4, Y14, Y9 (VEX, AVX-VNNI)
    ADDQ $64, SI
    ADDQ $64, DI
    DECQ CX
    JNZ lvv_loop64

lvv_tail32:
    TESTQ $32, DX
    JZ lvv_fold
    VMOVDQU (SI), Y6
    VMOVDQU (DI), Y7
    VPMAXUB Y7, Y6, Y2
    VPMINUB Y7, Y6, Y3
    VPSUBB Y3, Y2, Y2
    VPXOR Y4, Y2, Y3
    LONG $0x506DE2C4; BYTE $0xC3 // VPDPBUSD Y3, Y2, Y0 (VEX, AVX-VNNI)
    LONG $0x506D62C4; BYTE $0xC4 // VPDPBUSD Y4, Y2, Y8 (VEX, AVX-VNNI)
